import React, { useEffect, useState } from 'react';
import { useSearchParams } from 'react-router-dom';
import api from '../api';

const Chat = () => {
  const [searchParams] = useSearchParams();
  const [users, setUsers] = useState([]);
  const [selectedUser, setSelectedUser] = useState(null);
  const [messages, setMessages] = useState([]);
  const [messageText, setMessageText] = useState('');

  useEffect(() => {
    const loadUsers = async () => {
      try {
        const res = await api.get('admin/users');
        setUsers(res.data.filter((u) => Number(u.id) !== Number(localStorage.getItem('userId'))));
      } catch (err) {
        console.error(err);
      }
    };
    loadUsers();
  }, []);

  useEffect(() => {
    const paramUser = Number(searchParams.get('user'));
    if (paramUser) {
      setSelectedUser(paramUser);
    }
  }, [searchParams]);

  useEffect(() => {
    if (!selectedUser) return;
    const loadConversation = async () => {
      try {
        const res = await api.get(`chat/history/${selectedUser}`);
        setMessages(res.data);
      } catch (err) {
        console.error(err);
      }
    };
    loadConversation();
  }, [selectedUser]);

  const sendMessage = async () => {
    if (!selectedUser || !messageText) return;
    try {
      await api.post('chat/send', { receiverId: selectedUser, content: messageText, productId: null });
      setMessageText('');
      const res = await api.get(`chat/history/${selectedUser}`);
      setMessages(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  return (
    <div style={{ display: 'flex', gap: 20 }}>
      <div style={{ width: '30%' }}>
        <h4>Users</h4>
        {users.map((u) => (
          <button key={u.id} onClick={() => setSelectedUser(u.id)} style={{ display: 'block', width: '100%', margin: '4px 0' }}>
            {u.name} ({u.email})
          </button>
        ))}
      </div>
      <div style={{ width: '70%' }}>
        <h4>Chat</h4>
        {selectedUser ? (
          <>
            <div style={{ minHeight: 300, border: '1px solid #ccc', padding: 10 }}>
              {messages.map((msg) => (
                <div key={msg.id} style={{ textAlign: Number(msg.senderId) === Number(localStorage.getItem('userId')) ? 'right' : 'left' }}>
                  <p><strong>{msg.senderName}</strong>: {msg.content}</p>
                </div>
              ))}
            </div>
            <div>
              <input value={messageText} onChange={(e) => setMessageText(e.target.value)} placeholder="Message" />
              <button onClick={sendMessage}>Send</button>
            </div>
          </>
        ) : (
          <p>Select a user to start chatting</p>
        )}
      </div>
    </div>
  );
};

export default Chat;
